import React from "react";

function Geeting(props) {
  return (
    <div>
      <h1>Welcome to React</h1>
      <p>{props.value}</p>
    </div>
  );
}

function Apps(props) {
  return (
    <>
      <h1>Welcome to React</h1>
      <p>{props.value}</p>
    </>
  );
}
export { Geeting };
